#include <stdio.h>

int main() {
    int n, x;

    scanf("%d %d", &n, &x);

    int arr[n];

    for(int i = 0; i < n; i++){
        scanf("%d ", &arr[i]);
    }

    int found = 0;
    for(int i = 0; i < n; i++){
        if(arr[i] == x){
            found = 1;
            break;
        }
    }

    if(found == 1)
      printf("YES");
    else 
      printf("NO");

    return 0;
}
